changeSet.sql:
UPDATE promo_codes pc
SET current_usage_count = (
    SELECT COUNT(*)
    FROM promo_code_usage pcu
    WHERE pcu.promo_code_id = pc.id
);

DO $$ DECLARE v_inconsistent_count INT; v_samples TEXT; BEGIN -- Проверяем что current_usage_count совпадает с реальными данными SELECT COUNT(*) INTO v_inconsistent_count FROM promo_codes pc WHERE pc.current_usage_count != ( SELECT COUNT(*) FROM promo_code_usage pcu WHERE pcu.promo_code_id = pc.id );
IF v_inconsistent_count > 0 THEN -- Собираем примеры для диагностики SELECT string_agg( pc.code || ': counter=' || pc.current_usage_count::TEXT || ', actual=' || ( SELECT COUNT(*)::TEXT FROM promo_code_usage pcu WHERE pcu.promo_code_id = pc.id ), ', ' ) INTO v_samples FROM promo_codes pc WHERE pc.current_usage_count != ( SELECT COUNT(*) FROM promo_code_usage pcu WHERE pcu.promo_code_id = pc.id ) LIMIT 5;
RAISE EXCEPTION 'Data consistency check FAILED after counter recalculation: ' '% promo code(s) still have incorrect counters: [%]', v_inconsistent_count, v_samples; END IF;
RAISE NOTICE 'Verification PASSED: all % promo code counters are consistent with promo_code_usage.', (SELECT COUNT(*) FROM promo_codes); END $$;

rollback.sql:
COMMENT ON COLUMN promo_codes.current_usage_count IS
'Current number of times this promo code has been used.
IMPORTANT: This counter is now persistent and incremented transactionally.';
